import { ref } from 'vue'
import { updateNickname } from '@/api/user'
import { showToast } from '@/components/ToastMessage'

export function useNickname() {
  const value = ref('')
  const loading = ref(false)

  const handleUpdate = async () => {
    if (!value.value.trim()) {
      showToast('昵称不能为空', 'error')
      return
    }

    loading.value = true
    try {
      await updateNickname(value.value)
      showToast('昵称修改成功', 'success')
      return true
    } catch (error) {
      showToast(error.message || '修改失败', 'error')
      return false
    } finally {
      loading.value = false
    }
  }

  return {
    value,
    loading,
    handleUpdate
  }
}
